    private void go() {

        Map<LocalDate, List<Squadre>> map = new HashMap<>();
        fillOct2025(map);
        fillNov2025(map);
        fillDec2025(map);
        fillJan2026(map);
        fillFeb2026(map);
        fillMar2026(map);
        fillApr2026(map);
        List<LocalDate> completionDates = findCompletionDates(map, LocalDate.of(2025,10,22), LocalDate.of(2026,4,13));
        printCompletionDates(completionDates);
    }

    private List<LocalDate> findCompletionDates(Map<LocalDate, List<Squadre>> map, LocalDate start, LocalDate end) {
        Set<Squadre> allTeams = EnumSet.allOf(Squadre.class);
        Set<Squadre> seen = EnumSet.noneOf(Squadre.class);
        List<LocalDate> completionDates = new ArrayList<>();
        LocalDate cursor = start;
        while (!cursor.isAfter(end)) {
            List<Squadre> teams = map.get(cursor);
            if (teams != null) {
                seen.addAll(teams);
                if (seen.containsAll(allTeams)) {
                    completionDates.add(cursor);
                    seen.clear();
                }
            }
            cursor = cursor.plusDays(1);
        }
        return completionDates;
    }

    private void printCompletionDates(List<LocalDate> dates) {
        LocalDate prev = null;
        for (LocalDate date : dates) {
            long delta = prev == null ? 0 : ChronoUnit.DAYS.between(prev, date);
            System.out.println(date + " (" + delta + " giorni)");
            prev = date;
        }
    }
